echo "Inserting articles...\n";
$total = 0;

foreach ($categories as $key => $catId) {
    $articles = $data[$key];

    foreach ($articles as $art) {
        $title = $art['t'];
        $image = $art['i'];
        $desc = $art['d'];

        $slug = strtolower(preg_replace('/[^a-z0-9]+/i', '-', $title)) . '-' . uniqid();

        $content = $desc . "\n\n";
        for ($i = 0; $i < rand(10, 15); $i++) {
            $content .= $paragraphs[array_rand($paragraphs)] . ' ';
            $content .= $paragraphs[array_rand($paragraphs)] . "\n\n";
        }

        $views = rand(100, 5000);
        $created = date('Y-m-d H:i:s', strtotime('-' . rand(1, 180) . ' days'));

        $stmt = $db->prepare("INSERT INTO articles (title, slug, description, content, image, views, created_at) VALUES (?, ?, ?, ?, ?, ?, ?)");
        $stmt->execute([$title, $slug, $desc, $content, $image, $views, $created]);

        $aid = $db->lastInsertId();
        $db->prepare("INSERT INTO article_categories (article_id, category_id) VALUES (?, ?)")->execute([$aid, $catId]);

        $total++;
    }

    echo "  " . $categoryNames[$catId] . ": " . count($articles) . " articles\n";
}

echo "\n✓ Total inserted: $total articles\n";
echo "\nSeeding completed successfully!\n";
